    const META_LABELS = ["Анализ и прогнозирование", "Достижение результата", "Лидерство в изменениях", "Организованность", "Ориентация на клиента", "Работа в команде", "Стремление к совершенству", "Эффективная коммуникация"];
    const NEED_LABELS = ["Оплата труда", "Социальная поддержка", "Самостоятельность", "Баланс работы и личной жизни", "Обратная связь", "Комфорт", "Доступность ресурсов", "Признание заслуг"];
    const STAGE_ORDER = ["Равновесия", "Напряженности", "Истощения", "Бессилия"];

    const PERSONAL_METRICS = [
      { key: "integratedScore", label: "Интегральный индекс", direction: "desc", kind: "strength" },
      { key: "potential", label: "Индекс потенциала", direction: "desc", kind: "strength" },
      { key: "deltaMetaMean", label: "Метакомпетенции", direction: "desc", kind: "strength" },
      { key: "switchOverall", label: "Switch", direction: "desc", kind: "strength" },
      { key: "conditionsMean", label: "Организационные условия", direction: "desc", kind: "strength" },
      { key: "burnoutOverall", label: "Выгорание", direction: "desc", kind: "risk" },
      { key: "detachmentOverall", label: "Дистанцирование", direction: "desc", kind: "risk" }
    ];

    const STAGE_TITLE = {
      "Равновесия": "Равновесие",
      "Напряженности": "Напряженность",
      "Истощения": "Истощение",
      "Бессилия": "Бессилие"
    };

    const stageColor = {
      "Равновесия": "stage-0",
      "Напряженности": "stage-1",
      "Истощения": "stage-2",
      "Бессилия": "stage-3"
    };

    const globalMetricSelect = document.getElementById("globalMetricSelect");
    const compareDeptOneSelect = document.getElementById("compareDeptOneSelect");
    const compareDeptTwoSelect = document.getElementById("compareDeptTwoSelect");
    const compareMetricSelect = document.getElementById("compareMetricSelect");
    const profileDepartmentSelect = document.getElementById("profileDepartmentSelect");
    const profileMetricSelect = document.getElementById("profileMetricSelect");
    const roleFilter = document.getElementById("roleFilter");
    const personalMetricSelect = document.getElementById("personalMetricSelect");
    const resetButton = document.getElementById("resetButton");
    const exportWordButton = document.getElementById("exportWordButton");
    const exportPdfButton = document.getElementById("exportPdfButton");

    const fmt = {
      score: (value) => value == null ? "—" : Number(value).toFixed(1),
      percent: (value) => value == null ? "—" : `${Number(value).toFixed(1)}%`,
      integer: (value) => value == null ? "—" : String(value),
    };

    function roundValue(value, digits = 1) {
      if (value == null || Number.isNaN(Number(value))) return null;
      return Number(Number(value).toFixed(digits));
    }

    function getMetricMeta(key) {
      return DATA.metrics.find(metric => metric.key === key) || DATA.metrics[0];
    }

    function getPersonalMetricMeta(key) {
      return PERSONAL_METRICS.find(metric => metric.key === key) || PERSONAL_METRICS[0];
    }

    function getDepartmentByName(name) {
      return DATA.departments.find(item => item.department === name) || DATA.departments[0];
    }

    function toCamel(key) {
      const map = {
        integrated_score: "integratedScore",
        delta_meta_mean: "deltaMetaMean",
        switch_overall: "switchOverall",
        fade_burnout_overall: "burnoutOverall",
        fade_detachment_overall: "detachmentOverall",
        fade_need_mean: "conditionsMean",
        high_burnout_share_pct: "highBurnoutShare",
        high_detachment_share_pct: "highDetachmentShare",
        mean_potential: "meanPotential"
      };
      return map[key] || key;
    }

    function metricValue(dep, metric) {
      return dep[toCamel(metric.key)];
    }

    function meanBy(items, key) {
      const values = items.map(item => item[key]).filter(value => value != null);
      if (!values.length) return null;
      return roundValue(values.reduce((sum, value) => sum + value, 0) / values.length, 1);
    }

    function shareBy(items, key) {
      if (!items.length) return 0;
      return roundValue(items.filter(item => Boolean(item[key])).length / items.length * 100, 1);
    }

    function aggregateProfile(people, fieldName, labels) {
      const profile = {};
      labels.forEach(label => {
        const values = people
          .map(person => person[fieldName] ? person[fieldName][label] : null)
          .filter(value => value != null);
        profile[label] = values.length
          ? roundValue(values.reduce((sum, value) => sum + value, 0) / values.length, 1)
          : null;
      });
      return profile;
    }

    function topProfileLabel(profile, reverse = true) {
      const items = Object.entries(profile).filter(([, value]) => value != null);
      if (!items.length) return "—";
      items.sort((a, b) => reverse ? b[1] - a[1] : a[1] - b[1]);
      return items[0][0];
    }

    function buildCounts(people, key) {
      const counters = new Map();
      people.forEach(person => {
        const label = person[key] || "—";
        counters.set(label, (counters.get(label) || 0) + 1);
      });
      return [...counters.entries()]
        .map(([label, count]) => ({ label, count }))
        .sort((a, b) => b.count - a.count || a.label.localeCompare(b.label, "ru"));
    }

    function buildSubdivisions(people) {
      const buckets = new Map();
      people
        .filter(person => person.subdivision && person.subdivision !== "—")
        .forEach(person => {
          const current = buckets.get(person.subdivision) || [];
          current.push(person);
          buckets.set(person.subdivision, current);
        });

      return [...buckets.entries()]
        .map(([subdivision, items]) => ({
          subdivision,
          n: items.length,
          integratedScore: meanBy(items, "integratedScore"),
          switchOverall: meanBy(items, "switchOverall"),
          burnoutOverall: meanBy(items, "burnoutOverall"),
          detachmentOverall: meanBy(items, "detachmentOverall"),
        }))
        .sort((a, b) => (b.integratedScore ?? -999) - (a.integratedScore ?? -999))
        .slice(0, 20);
    }

    function majorStage(stageCounts) {
      const items = Object.entries(stageCounts);
      if (!items.length) return "—";
      items.sort((a, b) => b[1] - a[1]);
      return items[0][0];
    }

    function formatStage(stage) {
      return STAGE_TITLE[stage] || stage || "—";
    }

    function buildSlice(dep, roleValue) {
      const allPeople = dep.people || [];
      const people = roleValue === "all"
        ? allPeople
        : allPeople.filter(person => person.roleGroup === roleValue);

      const stageCounts = {};
      STAGE_ORDER.forEach(stage => {
        stageCounts[stage] = people.filter(person => person.stage === stage).length;
      });

      const slice = {
        roleValue,
        people,
        n: people.length,
        integratedScore: meanBy(people, "integratedScore"),
        deltaMetaMean: meanBy(people, "deltaMetaMean"),
        switchOverall: meanBy(people, "switchOverall"),
        burnoutOverall: meanBy(people, "burnoutOverall"),
        detachmentOverall: meanBy(people, "detachmentOverall"),
        conditionsMean: meanBy(people, "conditionsMean"),
        meanPotential: meanBy(people, "potential"),
        highBurnoutShare: shareBy(people, "highBurnout"),
        highDetachmentShare: shareBy(people, "highDetachment"),
        resourceRiskShare: shareBy(people, "resourceRisk"),
        resourceWatchShare: shareBy(people, "resourceWatch"),
        resourceRiskCount: people.filter(person => person.resourceRisk).length,
        resourceWatchCount: people.filter(person => person.resourceWatch).length,
        stageCounts,
        stageMajor: majorStage(stageCounts),
        metaProfile: aggregateProfile(people, "metaProfile", META_LABELS),
        needProfile: aggregateProfile(people, "needProfile", NEED_LABELS),
        roleCounts: buildCounts(people, "roleGroup"),
        positionCounts: buildCounts(people, "roleGroup"),
        subdivisions: buildSubdivisions(people),
      };

      slice.strongestMeta = topProfileLabel(slice.metaProfile, true);
      slice.weakestMeta = topProfileLabel(slice.metaProfile, false);
      slice.strongestNeed = topProfileLabel(slice.needProfile, true);
      slice.weakestNeed = topProfileLabel(slice.needProfile, false);
      slice.riskPeople = [...people]
        .sort((a, b) => (b.burnoutOverall ?? -999) - (a.burnoutOverall ?? -999) || (b.detachmentOverall ?? -999) - (a.detachmentOverall ?? -999))
        .slice(0, 8);
      slice.potentialPeople = [...people]
        .sort((a, b) => (b.potential ?? -999) - (a.potential ?? -999) || (b.deltaMetaMean ?? -999) - (a.deltaMetaMean ?? -999))
        .slice(0, 8);
      return slice;
    }

    function getDepartmentsSorted(metricKey) {
      const metric = getMetricMeta(metricKey);
      return [...DATA.departments].sort((a, b) => {
        const av = metricValue(a, metric);
        const bv = metricValue(b, metric);
        if (metric.direction === "asc") return (av ?? 0) - (bv ?? 0);
        return (bv ?? 0) - (av ?? 0);
      });
    }

    function getSliceProfileType(slice) {
      if ((slice.burnoutOverall ?? 0) >= 45 || (slice.highBurnoutShare ?? 0) >= 20) return "Зона кадрового риска";
      if ((slice.deltaMetaMean ?? 0) >= 50 && (slice.burnoutOverall ?? 0) >= 35) return "Сильные, но перегруженные";
      if ((slice.deltaMetaMean ?? 0) >= 50 && (slice.conditionsMean ?? 0) >= 50) return "Сильные и устойчивые";
      if ((slice.conditionsMean ?? 0) < 45) return "Организационное напряжение";
      return "Средние, но стабильные";
    }

    function deviationText(value, average, lowerIsBetter = false) {
      if (value == null || average == null) return "данных недостаточно для сравнения";
      const delta = roundValue(value - average, 1);
      if (Math.abs(delta) < 1) return "на уровне среднего по выборке";
      if (lowerIsBetter) {
        return delta <= 0
          ? `ниже среднего по выборке на ${fmt.score(Math.abs(delta))}`
          : `выше среднего по выборке на ${fmt.score(delta)}`;
      }
      return delta >= 0
        ? `выше среднего по выборке на ${fmt.score(delta)}`
        : `ниже среднего по выборке на ${fmt.score(Math.abs(delta))}`;
    }

    function buildPriorityActions(slice) {
      const actions = [];
      if ((slice.highBurnoutShare ?? 0) >= 20 || (slice.burnoutOverall ?? 0) >= (DATA.summary.meanBurnout ?? 0) + 5) {
        actions.push("Снизить очаги перегрузки: проверить распределение задач, дедлайны и управленческую нагрузку в наиболее напряжённых подразделениях.");
      }
      if (["Баланс работы и личной жизни", "Доступность ресурсов", "Комфорт", "Оплата труда"].includes(slice.weakestNeed)) {
        actions.push(`Отдельно проработать дефицит по блоку «${slice.weakestNeed}», так как именно он сейчас сильнее всего ограничивает устойчивость сотрудников.`);
      }
      if ((slice.deltaMetaMean ?? 0) < (DATA.summary.meanMeta ?? 0)) {
        actions.push("Добавить точечные управленческие и командные развивающие меры для тех ролей, где проседают метакомпетенции.");
      }
      if ((slice.meanPotential ?? 0) >= (DATA.summary.meanPotential ?? 0)) {
        actions.push("Использовать сотрудников с высоким потенциалом как опорную группу для наставничества, передачи практик и удержания стабильности.");
      }
      if (!actions.length) {
        actions.push("Сохранять текущий баланс, но регулярно отслеживать динамику выгорания, чтобы не пропустить накопление скрытой перегрузки.");
      }
      return actions.slice(0, 4);
    }

    function buildNarrativeModel(dep, slice, metric, rankingPos) {
      const scopeLabel = slice.roleValue === "all"
        ? `по всему органу власти ${dep.department}`
        : `по должности «${slice.roleValue}» внутри органа ${dep.department}`;
      const profileType = getSliceProfileType(slice);
      const participants = `<strong>${fmt.integer(slice.n)}</strong>`;
      const paragraphs = [
        `Срез ${scopeLabel} охватывает ${participants} чел. По общему рейтингу органов власти ${dep.department} занимает <strong>${fmt.integer(dep.overallRank)}</strong> место из <strong>${DATA.departments.length}</strong>, а по показателю «${metric.label}» — <strong>${fmt.integer(rankingPos)}</strong> место. По текущему срезу профиль можно описать как <strong>${profileType.toLowerCase()}</strong>.`,
        `Интегральный индекс среза составляет <strong>${fmt.score(slice.integratedScore)}</strong>, что ${deviationText(slice.integratedScore, DATA.summary.meanIntegrated, false)}. Метакомпетенции находятся на уровне <strong>${fmt.score(slice.deltaMetaMean)}</strong>, Switch — <strong>${fmt.score(slice.switchOverall)}</strong>, а средний потенциал — <strong>${fmt.score(slice.meanPotential)}</strong>. Наиболее сильная метакомпетенция — <strong>${slice.strongestMeta}</strong>, наиболее уязвимая — <strong>${slice.weakestMeta}</strong>.`,
        `По состоянию сотрудников виден следующий контур риска: среднее выгорание — <strong>${fmt.score(slice.burnoutOverall)}</strong> (${deviationText(slice.burnoutOverall, DATA.summary.meanBurnout, true)}), дистанцирование — <strong>${fmt.score(slice.detachmentOverall)}</strong> (${deviationText(slice.detachmentOverall, DATA.summary.meanDetachment, true)}). Доля высокого выгорания достигает <strong>${fmt.percent(slice.highBurnoutShare)}</strong>, доля высокого дистанцирования — <strong>${fmt.percent(slice.highDetachmentShare)}</strong>. В зоне выраженного ресурсного риска находятся <strong>${fmt.integer(slice.resourceRiskCount)}</strong> чел., в зоне наблюдения — <strong>${fmt.integer(slice.resourceWatchCount)}</strong> чел.`,
        `Организационная среда в текущем срезе оценивается на <strong>${fmt.score(slice.conditionsMean)}</strong>, что ${deviationText(slice.conditionsMean, DATA.summary.meanConditions, false)}. Лучше всего сотрудники ощущают поддержку по блоку <strong>${slice.strongestNeed}</strong>, а наиболее дефицитным сейчас выглядит блок <strong>${slice.weakestNeed}</strong>. Преобладающая стадия состояния — <strong>${formatStage(slice.stageMajor)}</strong>.`
      ];
      return {
        title: slice.roleValue === "all" ? dep.department : `${dep.department} — ${slice.roleValue}`,
        subtitle: slice.roleValue === "all"
          ? "Полный срез по органу власти"
          : "Локальный срез по выбранной должности",
        badges: [
          profileType,
          `Ведущая стадия: ${formatStage(slice.stageMajor)}`,
          `Сильная сторона: ${slice.strongestMeta}`,
          `Дефицит среды: ${slice.weakestNeed}`
        ],
        paragraphs,
        actions: buildPriorityActions(slice)
      };
    }

    function sortPeopleByMetric(people, metric) {
      return [...people].sort((a, b) => {
        const av = a[metric.key];
        const bv = b[metric.key];
        if (metric.direction === "asc") return (av ?? 0) - (bv ?? 0);
        return (bv ?? 0) - (av ?? 0);
      });
    }

    function renderGlobalStats() {
      const stats = [
        ["Участников", DATA.summary.people],
        ["Органов власти", DATA.summary.departments],
        ["Высокое выгорание", DATA.summary.highBurnout],
        ["Высокое дистанцирование", DATA.summary.highDetachment],
        ["Зона ресурсного риска", DATA.summary.resourceRisk],
        ["Зона наблюдения", DATA.summary.resourceWatch],
      ];
      document.getElementById("globalStats").innerHTML = stats.map(([label, value]) => `
        <div class="stat">
          <div class="label">${label}</div>
          <div class="value">${value}</div>
        </div>
      `).join("");
    }

    function departmentOptionsHtml() {
      return [...DATA.departments]
        .sort((a, b) => a.department.localeCompare(b.department, "ru"))
        .map(dep => `<option value="${dep.department}">${dep.department}</option>`)
        .join("");
    }

    function populateGlobalOptions() {
      globalMetricSelect.innerHTML = DATA.metrics
        .map(metric => `<option value="${metric.key}">${metric.label}</option>`)
        .join("");
      globalMetricSelect.value = "fade_burnout_overall";
    }

    function populateComparisonOptions() {
      const options = departmentOptionsHtml();
      compareDeptOneSelect.innerHTML = options;
      compareDeptTwoSelect.innerHTML = options;
      compareDeptOneSelect.selectedIndex = 0;
      compareDeptTwoSelect.selectedIndex = Math.min(1, compareDeptTwoSelect.options.length - 1);

      compareMetricSelect.innerHTML = DATA.metrics
        .map(metric => `<option value="${metric.key}">${metric.label}</option>`)
        .join("");
      compareMetricSelect.value = "integrated_score";
    }

    function populateProfileOptions() {
      profileDepartmentSelect.innerHTML = departmentOptionsHtml();
      profileMetricSelect.innerHTML = DATA.metrics
        .map(metric => `<option value="${metric.key}">${metric.label}</option>`)
        .join("");
      profileMetricSelect.value = "fade_burnout_overall";
    }

    function populateInternalOptions() {
      personalMetricSelect.innerHTML = PERSONAL_METRICS
        .map(metric => `<option value="${metric.key}">${metric.label}</option>`)
        .join("");
      personalMetricSelect.value = "integratedScore";
    }

    function populateRoleFilter(selectedDepartment, keepValue = "all") {
      const dep = getDepartmentByName(selectedDepartment);
      const positions = [...new Set((dep.people || []).map(person => person.roleGroup).filter(Boolean))]
        .sort((a, b) => a.localeCompare(b, "ru"));
      roleFilter.innerHTML = [`<option value="all">Все должности</option>`]
        .concat(positions.map(position => `<option value="${position}">${position}</option>`))
        .join("");
      roleFilter.value = positions.includes(keepValue) ? keepValue : "all";
    }

    function renderRanking(selectedDepartment, metricKey, mode) {
      const metric = getMetricMeta(metricKey);
      const sorted = getDepartmentsSorted(metricKey);
      const values = sorted.map(dep => metricValue(dep, metric)).filter(v => v != null);
      const max = Math.max(...values, 1);
      const bars = sorted
        .filter((dep, index) => mode === "all" || dep.department === selectedDepartment || index < 6)
        .map((dep, index) => {
          const value = metricValue(dep, metric);
          const width = value == null ? 0 : Math.max(8, (value / max) * 100);
          const active = dep.department === selectedDepartment;
          return `
            <div class="bar-item">
              <div>
                <div class="bar-meta">
                  <span><strong>${index + 1}.</strong> ${dep.department}</span>
                  <span class="${metric.kind === "risk" ? "score-risk" : "score-good"}">${fmt[metric.format](value)}</span>
                </div>
                <div class="bar-track">
                  <div class="bar-fill ${metric.kind === "risk" ? "risk-fill" : ""}" style="width:${width}%; opacity:${active ? 1 : 0.8}"></div>
                </div>
              </div>
            </div>
          `;
        }).join("");

      document.getElementById("rankingTitle").textContent = `Рейтинг по показателю: ${metric.label}`;
      document.getElementById("rankingSub").textContent = metric.kind === "risk"
        ? "В этом режиме наверху находятся органы власти с наиболее выраженным риском по выбранному показателю."
        : "В этом режиме наверху находятся органы власти с наиболее сильным профилем по выбранному показателю.";
      document.getElementById("rankingBars").innerHTML = bars;

      document.getElementById("rankingTable").innerHTML = sorted.map((dep, index) => `
        <tr class="${dep.department === selectedDepartment ? "highlight" : ""}">
          <td>${index + 1}</td>
          <td>${dep.department}</td>
          <td>${fmt[metric.format](metricValue(dep, metric))}</td>
          <td>${dep.n}</td>
          <td>${fmt.score(dep.integratedScore)}</td>
          <td>${fmt.score(dep.burnoutOverall)}</td>
        </tr>
      `).join("");
    }

    function renderStageMatrix(selectedDepartment, metricKey) {
      const sorted = getDepartmentsSorted(metricKey);
      document.getElementById("stageMatrix").innerHTML = sorted.map(dep => {
        const total = dep.n || 1;
        const active = dep.department === selectedDepartment;
        const segments = Object.entries(dep.stageCounts).map(([stage, count]) => {
          const width = count / total * 100;
          return `<div class="stage-segment ${stageColor[stage] || ""}" style="width:${width}%; opacity:${active ? 1 : 0.78}"></div>`;
        }).join("");
        return `
          <div class="stage-row">
            <div style="font-weight:${active ? 800 : 600};">${dep.department}</div>
            <div class="stage-stack">${segments}</div>
            <div class="muted">${dep.n}</div>
          </div>
        `;
      }).join("");
    }

    function renderGlobalSummary(metricKey) {
      const metric = getMetricMeta(metricKey);
      const sorted = getDepartmentsSorted(metricKey);
      const top = sorted[0];
      const bottom = sorted[sorted.length - 1];
      const spread = top && bottom
        ? roundValue((metricValue(top, metric) ?? 0) - (metricValue(bottom, metric) ?? 0), 1)
        : null;
      const riskMode = metric.kind === "risk";
      document.getElementById("globalSummaryTitle").textContent = `Общая картина по показателю «${metric.label}»`;
      document.getElementById("globalSummarySub").textContent = riskMode
        ? "Чем выше значение, тем более выражен риск по выбранному показателю."
        : "Чем выше значение, тем сильнее профиль органа власти по выбранному показателю.";
      document.getElementById("globalSummaryBadges").innerHTML = [
        `Лидер: ${top ? top.department : "—"}`,
        `Последняя позиция: ${bottom ? bottom.department : "—"}`,
        `Разброс: ${spread == null ? "—" : fmt.score(spread)}`
      ].map(item => `<span class="report-badge">${item}</span>`).join("");

      const text = top && bottom
        ? [
            `По показателю «${metric.label}» верхнюю позицию сейчас занимает <strong>${top.department}</strong> со значением <strong>${fmt[metric.format](metricValue(top, metric))}</strong>.`,
            riskMode
              ? `На другом конце распределения находится <strong>${bottom.department}</strong> со значением <strong>${fmt[metric.format](metricValue(bottom, metric))}</strong>, то есть риск там выражен слабее.`
              : `Нижнюю позицию занимает <strong>${bottom.department}</strong> со значением <strong>${fmt[metric.format](metricValue(bottom, metric))}</strong>, что показывает наиболее слабый профиль по этому показателю.`,
            `Разница между крайними позициями составляет <strong>${spread == null ? "—" : fmt.score(spread)}</strong>, поэтому показатель помогает довольно чётко разделить органы власти по уровню выраженности профиля.`,
          ]
        : ["Недостаточно данных для общей интерпретации."];

      document.getElementById("globalSummaryNarrative").innerHTML = text.map(item => `<p>${item}</p>`).join("");
    }

    function renderCompareDepartmentCard(targetId, dep, metric) {
      const ranking = getDepartmentsSorted(metric.key);
      const rank = ranking.findIndex(item => item.department === dep.department) + 1;
      document.getElementById(targetId).innerHTML = `
        <div class="section-label">Орган власти</div>
        <h2>${dep.department}</h2>
        <p class="sub">Общее место: ${dep.overallRank} из ${DATA.departments.length}. По показателю «${metric.label}» — ${rank} место.</p>
        <div class="comparison-value ${metric.kind === "risk" ? "score-risk" : "score-good"}">${fmt[metric.format](metricValue(dep, metric))}</div>
        <div class="comparison-note">Текущее значение по выбранному показателю</div>
        <div class="comparison-kpis">
          <div class="mini-card"><div class="k">Интегральный индекс</div><div class="v">${fmt.score(dep.integratedScore)}</div></div>
          <div class="mini-card"><div class="k">Выгорание</div><div class="v">${fmt.score(dep.burnoutOverall)}</div></div>
          <div class="mini-card"><div class="k">Метакомпетенции</div><div class="v">${fmt.score(dep.deltaMetaMean)}</div></div>
          <div class="mini-card"><div class="k">Участников</div><div class="v">${fmt.integer(dep.n)}</div></div>
        </div>
      `;
    }

    function renderDepartmentComparison(depOne, depTwo, metricKey) {
      const metric = getMetricMeta(metricKey);
      const valueOne = metricValue(depOne, metric);
      const valueTwo = metricValue(depTwo, metric);
      const delta = roundValue((valueOne ?? 0) - (valueTwo ?? 0), 1);
      const absDelta = delta == null ? null : Math.abs(delta);
      const leader = metric.kind === "risk"
        ? (valueOne ?? -999) >= (valueTwo ?? -999) ? depOne.department : depTwo.department
        : (valueOne ?? -999) >= (valueTwo ?? -999) ? depOne.department : depTwo.department;
      const strongerText = metric.kind === "risk"
        ? `${leader} показывает более высокий риск по выбранному показателю.`
        : `${leader} показывает более сильный профиль по выбранному показателю.`;
      const maxValue = Math.max(Math.abs(valueOne ?? 0), Math.abs(valueTwo ?? 0), 1);
      const width = absDelta == null ? 0 : Math.max(8, absDelta / maxValue * 100);

      renderCompareDepartmentCard("compareDeptOneCard", depOne, metric);
      renderCompareDepartmentCard("compareDeptTwoCard", depTwo, metric);
      document.getElementById("compareCenterTitle").textContent = `Сопоставление по показателю «${metric.label}»`;
      document.getElementById("compareCenterSub").textContent = `${depOne.department} против ${depTwo.department}`;
      document.getElementById("compareCenterValue").textContent = absDelta == null ? "—" : fmt.score(absDelta);
      document.getElementById("compareCenterDelta").textContent = strongerText;
      document.getElementById("compareCenterBar").style.width = `${width}%`;
      document.getElementById("compareCenterBar").className = `bar-fill ${metric.kind === "risk" ? "risk-fill" : ""}`;
      document.getElementById("compareCenterNote").innerHTML = `
        Значение ${depOne.department}: <strong>${fmt[metric.format](valueOne)}</strong><br />
        Значение ${depTwo.department}: <strong>${fmt[metric.format](valueTwo)}</strong><br />
        Разница: <strong>${delta == null ? "—" : (delta > 0 ? "+" : "") + delta}</strong>
      `;
    }

    function renderComparisonBars(targetId, values, overall, reverseMeaning) {
      document.getElementById(targetId).innerHTML = Object.entries(values).map(([label, value]) => {
        const overallValue = overall[label] ?? 0;
        const delta = value == null ? null : roundValue(value - overallValue, 1);
        const deltaLabel = delta == null ? "н/д" : delta > 0 ? `+${delta}` : String(delta);
        return `
          <div class="bar-item">
            <div>
              <div class="bar-meta">
                <span>${label}</span>
                <span>${fmt.score(value)} <span class="muted">/ среднее ${fmt.score(overallValue)} (${deltaLabel})</span></span>
              </div>
              <div class="bar-track">
                <div class="bar-fill ${reverseMeaning ? "risk-fill" : ""}" style="width:${value == null ? 0 : value}%"></div>
              </div>
            </div>
          </div>
        `;
      }).join("");
    }

    function renderDepartmentProfile(dep, slice, metric) {
      const ranking = getDepartmentsSorted(metric.key);
      const rankingPos = ranking.findIndex(item => item.department === dep.department) + 1;
      document.getElementById("deptTitle").textContent = dep.department;
      document.getElementById("deptSub").textContent = `Место в общем интегральном рейтинге: ${dep.overallRank} из ${DATA.departments.length}. В рейтинге по показателю «${metric.label}» орган власти занимает позицию ${rankingPos}.`;

      const kpis = [
        ["Участников", fmt.integer(slice.n)],
        ["Интегральный индекс", fmt.score(slice.integratedScore)],
        ["Метакомпетенции", fmt.score(slice.deltaMetaMean)],
        ["Switch", fmt.score(slice.switchOverall)],
        ["Выгорание", fmt.score(slice.burnoutOverall)],
        ["Дистанцирование", fmt.score(slice.detachmentOverall)],
      ];
      document.getElementById("deptKpis").innerHTML = kpis.map(([label, value]) => `
        <div class="mini-card">
          <div class="k">${label}</div>
          <div class="v">${value}</div>
        </div>
      `).join("");

      const insights = [
        `Преобладающая стадия состояния: <strong>${formatStage(slice.stageMajor)}</strong>.`,
        `Сильнейшая метакомпетенция: <strong>${slice.strongestMeta}</strong>, наиболее слабая: <strong>${slice.weakestMeta}</strong>.`,
        `Лучше всего поддержана потребность <strong>${slice.strongestNeed}</strong>, наиболее дефицитна — <strong>${slice.weakestNeed}</strong>.`,
        `Доля высокого выгорания: <strong>${fmt.percent(slice.highBurnoutShare)}</strong>, доля высокого дистанцирования: <strong>${fmt.percent(slice.highDetachmentShare)}</strong>.`,
        `Средний потенциал по срезу: <strong>${fmt.score(slice.meanPotential)}</strong>, зона ресурсного риска: <strong>${fmt.percent(slice.resourceRiskShare)}</strong>.`,
      ];
      document.getElementById("deptInsights").innerHTML = insights.map(item => `<li>${item}</li>`).join("");

      const positionCounts = buildCounts(dep.people || [], "roleGroup");
      document.getElementById("roleBreakdown").innerHTML = positionCounts.length
        ? positionCounts.map(item => `
            <div class="bar-item">
              <div>
                <div class="bar-meta">
                  <span>${item.label}</span>
                  <span>${item.count}</span>
                </div>
                <div class="bar-track"><div class="bar-fill" style="width:${dep.n ? item.count / dep.n * 100 : 0}%"></div></div>
              </div>
            </div>
          `).join("")
        : `<div class="empty">Нет данных по должностям.</div>`;

      renderComparisonBars("metaBars", slice.metaProfile, DATA.summary.overallMeta, false);
      renderComparisonBars("needBars", slice.needProfile, DATA.summary.overallNeeds, true);
      renderReportCard(dep, slice, metric, rankingPos);
    }

    function renderReportCard(dep, slice, metric, rankingPos) {
      const model = buildNarrativeModel(dep, slice, metric, rankingPos);
      document.getElementById("reportTitle").textContent = model.title;
      document.getElementById("reportSub").textContent = model.subtitle;
      document.getElementById("reportBadges").innerHTML = model.badges
        .map(item => `<span class="report-badge">${item}</span>`)
        .join("");
      document.getElementById("reportNarrative").innerHTML = model.paragraphs
        .map(item => `<p>${item}</p>`)
        .join("");
      document.getElementById("reportActions").innerHTML = model.actions
        .map(item => `<li>${item}</li>`)
        .join("");
    }

    function renderPeopleLists(slice) {
      const riskBox = document.getElementById("riskPeople");
      const potentialBox = document.getElementById("potentialPeople");

      riskBox.innerHTML = slice.riskPeople.length
        ? slice.riskPeople.map(person => `
            <div class="mini-card" style="margin-bottom:10px;">
              <div style="font-weight:800; margin-bottom:6px;">${person.name}</div>
              <div style="display:flex; gap:10px; flex-wrap:wrap; font-size:13px;">
                <span>Выгорание: <strong>${fmt.score(person.burnoutOverall)}</strong></span>
                <span>Дистанцирование: <strong>${fmt.score(person.detachmentOverall)}</strong></span>
                <span>Switch: <strong>${fmt.score(person.switchOverall)}</strong></span>
              </div>
            </div>
          `).join("")
        : `<div class="empty">Нет данных для списка риска.</div>`;

      potentialBox.innerHTML = slice.potentialPeople.length
        ? slice.potentialPeople.map(person => `
            <div class="mini-card" style="margin-bottom:10px;">
              <div style="font-weight:800; margin-bottom:6px;">${person.name}</div>
              <div style="display:flex; gap:10px; flex-wrap:wrap; font-size:13px;">
                <span>Потенциал: <strong>${fmt.score(person.potential)}</strong></span>
                <span>Delta: <strong>${fmt.score(person.deltaMetaMean)}</strong></span>
                <span>Switch: <strong>${fmt.score(person.switchOverall)}</strong></span>
              </div>
            </div>
          `).join("")
        : `<div class="empty">Нет данных для списка потенциала.</div>`;
    }

    function renderPersonalRanking(dep, slice) {
      const metric = getPersonalMetricMeta(personalMetricSelect.value);
      const sorted = sortPeopleByMetric(slice.people, metric);
      const top = sorted.slice(0, 3);

      document.getElementById("peopleRankingTitle").textContent = slice.roleValue === "all"
        ? `Персональный рейтинг внутри ${dep.department}`
        : `Персональный рейтинг: ${slice.roleValue}`;
      document.getElementById("peopleRankingSub").textContent = metric.kind === "risk"
        ? `Срез охватывает ${slice.n} чел. Наверху — сотрудники с наиболее выраженным риском по показателю «${metric.label}».`
        : `Срез охватывает ${slice.n} чел. Наверху — сотрудники с наиболее сильным профилем по показателю «${metric.label}».`;
      document.getElementById("peopleMetricHeader").textContent = metric.label;

      document.getElementById("peopleLeaderCards").innerHTML = top.length
        ? top.map((person, index) => `
            <div class="leader-card">
              <div class="leader-rank">${index + 1}</div>
              <div style="font-weight:800; line-height:1.35;">${person.name}</div>
              <div class="leader-metric ${metric.kind === "risk" ? "score-risk" : "score-good"}">${fmt.score(person[metric.key])}</div>
              <div class="small-note">
                Потенциал: ${fmt.score(person.potential)}<br />
                Выгорание: ${fmt.score(person.burnoutOverall)}<br />
                Стадия: ${formatStage(person.stage)}
              </div>
            </div>
          `).join("")
        : `<div class="empty">Нет сотрудников для выбранного среза.</div>`;

      document.getElementById("peopleRankingTable").innerHTML = sorted.length
        ? sorted.map((person, index) => `
            <tr>
              <td>${index + 1}</td>
              <td>${person.name}</td>
              <td>${person.subdivision}</td>
              <td>${fmt.score(person[metric.key])}</td>
              <td>${fmt.score(person.potential)}</td>
              <td>${fmt.score(person.burnoutOverall)}</td>
              <td>${formatStage(person.stage)}</td>
            </tr>
          `).join("")
        : `<tr><td colspan="7" class="muted">Нет данных для персонального рейтинга.</td></tr>`;
    }

    function renderSubdivisionTable(dep, slice) {
      document.getElementById("subdivisionSub").textContent = slice.roleValue === "all"
        ? "Подразделения отсортированы по интегральному индексу, чтобы можно было быстро увидеть внутренние контрасты внутри органа власти."
        : `Таблица показывает, как распределён выбранный должностной срез «${slice.roleValue}» по подразделениям внутри органа власти.`;

      document.getElementById("subdivisionTable").innerHTML = slice.subdivisions.length
        ? slice.subdivisions.map(item => `
            <tr>
              <td>${item.subdivision}</td>
              <td>${item.n}</td>
              <td>${fmt.score(item.integratedScore)}</td>
              <td>${fmt.score(item.switchOverall)}</td>
              <td>${fmt.score(item.burnoutOverall)}</td>
              <td>${fmt.score(item.detachmentOverall)}</td>
            </tr>
          `).join("")
        : `<tr><td colspan="6" class="muted">Нет данных по подразделениям для выбранного среза.</td></tr>`;
    }

    function getCurrentContext() {
      const dep = getDepartmentByName(profileDepartmentSelect.value);
      const metric = getMetricMeta(profileMetricSelect.value);
      const personalMetric = getPersonalMetricMeta(personalMetricSelect.value);
      const departmentSlice = buildSlice(dep, "all");
      const internalSlice = buildSlice(dep, roleFilter.value || "all");
      const ranking = getDepartmentsSorted(metric.key);
      const rankingPos = ranking.findIndex(item => item.department === dep.department) + 1;
      return { dep, metric, personalMetric, departmentSlice, internalSlice, rankingPos };
    }

    function renderTableHtml(headers, rows) {
      return `
        <table>
          <thead>
            <tr>${headers.map(label => `<th>${label}</th>`).join("")}</tr>
          </thead>
          <tbody>
            ${rows.map(row => `<tr>${row.map(cell => `<td>${cell}</td>`).join("")}</tr>`).join("")}
          </tbody>
        </table>
      `;
    }

    function buildExportHtml(context) {
      const { dep, metric, personalMetric, internalSlice, rankingPos } = context;
      const model = buildNarrativeModel(dep, internalSlice, metric, rankingPos);
      const peopleRows = sortPeopleByMetric(internalSlice.people, personalMetric).slice(0, 20).map((person, index) => [
        index + 1,
        person.name,
        person.subdivision,
        fmt.score(person[personalMetric.key]),
        fmt.score(person.potential),
        fmt.score(person.burnoutOverall),
        formatStage(person.stage)
      ]);
      const subdivisionRows = internalSlice.subdivisions.map(item => [
        item.subdivision,
        item.n,
        fmt.score(item.integratedScore),
        fmt.score(item.switchOverall),
        fmt.score(item.burnoutOverall),
        fmt.score(item.detachmentOverall)
      ]);
      const metaRows = META_LABELS.map(label => [
        label,
        fmt.score(internalSlice.metaProfile[label]),
        fmt.score(DATA.summary.overallMeta[label]),
        internalSlice.metaProfile[label] == null || DATA.summary.overallMeta[label] == null
          ? "—"
          : roundValue(internalSlice.metaProfile[label] - DATA.summary.overallMeta[label], 1)
      ]);
      const needRows = NEED_LABELS.map(label => [
        label,
        fmt.score(internalSlice.needProfile[label]),
        fmt.score(DATA.summary.overallNeeds[label]),
        internalSlice.needProfile[label] == null || DATA.summary.overallNeeds[label] == null
          ? "—"
          : roundValue(internalSlice.needProfile[label] - DATA.summary.overallNeeds[label], 1)
      ]);

      return `
<!doctype html>
<html lang="ru">
<head>
  <meta charset="utf-8" />
  <title>${model.title}</title>
  <style>
    body { font-family: Arial, sans-serif; color: #1f2933; margin: 28px; }
    h1, h2, h3 { color: #295d8a; margin: 0 0 12px; }
    h1 { font-size: 28px; }
    h2 { font-size: 20px; margin-top: 26px; }
    h3 { font-size: 16px; margin-top: 20px; }
    p, li { line-height: 1.55; font-size: 13px; }
    .meta { color: #66717c; font-size: 12px; margin-bottom: 18px; }
    .chips { margin: 12px 0 18px; }
    .chip { display: inline-block; margin: 0 8px 8px 0; padding: 8px 12px; border-radius: 999px; background: #e8f0f6; color: #295d8a; font-size: 12px; font-weight: 700; }
    .kpis { width: 100%; border-collapse: collapse; margin: 12px 0 18px; }
    table { width: 100%; border-collapse: collapse; margin: 10px 0 18px; font-size: 12px; }
    th, td { border: 1px solid #d6d6ce; padding: 8px; text-align: left; vertical-align: top; }
    th { background: #f5f3ed; text-transform: uppercase; letter-spacing: 0.04em; font-size: 11px; }
    ul { margin-top: 0; }
    .section { page-break-inside: avoid; }
  </style>
</head>
<body>
  <h1>${model.title}</h1>
  <div class="meta">Сформировано: ${DATA.generatedAt}. Срез: ${internalSlice.roleValue === "all" ? "все должности" : internalSlice.roleValue}. Основа общего сравнения: рейтинг органов власти по показателю «${metric.label}».</div>

  <div class="chips">${model.badges.map(item => `<span class="chip">${item}</span>`).join("")}</div>

      <div class="section">
    <h2>Ключевые показатели</h2>
    ${renderTableHtml(
      ["Показатель", "Значение"],
      [
        ["Участников", fmt.integer(internalSlice.n)],
        ["Интегральный индекс", fmt.score(internalSlice.integratedScore)],
        ["Метакомпетенции", fmt.score(internalSlice.deltaMetaMean)],
        ["Switch", fmt.score(internalSlice.switchOverall)],
        ["Выгорание", fmt.score(internalSlice.burnoutOverall)],
        ["Дистанцирование", fmt.score(internalSlice.detachmentOverall)],
        ["Организационные условия", fmt.score(internalSlice.conditionsMean)],
        ["Средний потенциал", fmt.score(internalSlice.meanPotential)],
        ["Доля высокого выгорания", fmt.percent(internalSlice.highBurnoutShare)],
        ["Доля высокого дистанцирования", fmt.percent(internalSlice.highDetachmentShare)]
      ]
    )}
  </div>

  <div class="section">
    <h2>Подробный вывод</h2>
    ${model.paragraphs.map(item => `<p>${item}</p>`).join("")}
    <h3>Приоритеты для внимания</h3>
    <ul>${model.actions.map(item => `<li>${item}</li>`).join("")}</ul>
  </div>

  <div class="section">
    <h2>Метакомпетенции</h2>
    ${renderTableHtml(["Метакомпетенция", "Срез", "Среднее", "Δ"], metaRows)}
  </div>

  <div class="section">
    <h2>Организационная среда</h2>
    ${renderTableHtml(["Потребность", "Срез", "Среднее", "Δ"], needRows)}
  </div>

  <div class="section">
    <h2>Персональный рейтинг</h2>
    ${renderTableHtml(["Место", "Сотрудник", "Подразделение", personalMetric.label, "Потенциал", "Выгорание", "Стадия"], peopleRows)}
  </div>

  <div class="section">
    <h2>Подразделения</h2>
    ${renderTableHtml(["Подразделение", "N", "Интегральный индекс", "Switch", "Выгорание", "Дистанцирование"], subdivisionRows)}
  </div>
</body>
</html>
      `;
    }

    function downloadTextFile(filename, mimeType, content) {
      const blob = new Blob(["\ufeff", content], { type: mimeType });
      const url = URL.createObjectURL(blob);
      const link = document.createElement("a");
      link.href = url;
      link.download = filename;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      URL.revokeObjectURL(url);
    }

    function makeExportFilename(context, ext) {
      const dept = context.dep.department.replace(/[\\/:*?"<>|]+/g, "").replace(/\s+/g, "_");
      const role = (context.internalSlice.roleValue === "all" ? "vse_dolzhnosti" : context.internalSlice.roleValue)
        .replace(/[\\/:*?"<>|]+/g, "")
        .replace(/\s+/g, "_");
      return `sevastopol_${dept}_${role}.${ext}`;
    }

    function exportWord() {
      const context = getCurrentContext();
      const html = buildExportHtml(context);
      downloadTextFile(makeExportFilename(context, "doc"), "application/msword", html);
    }

    function exportPdf() {
      const context = getCurrentContext();
      const html = buildExportHtml(context);
      const popup = window.open("", "_blank");
      if (!popup) {
        window.alert("Браузер заблокировал новое окно для печати PDF. Разрешите открытие всплывающих окон и повторите экспорт.");
        return;
      }
      popup.document.open();
      popup.document.write(html);
      popup.document.close();
      popup.focus();
      setTimeout(() => popup.print(), 300);
    }

    function update() {
      const { dep, metric, departmentSlice, internalSlice } = getCurrentContext();
      renderRanking("", globalMetricSelect.value, "all");
      renderStageMatrix("", globalMetricSelect.value);
      renderGlobalSummary(globalMetricSelect.value);
      renderDepartmentComparison(
        getDepartmentByName(compareDeptOneSelect.value),
        getDepartmentByName(compareDeptTwoSelect.value),
        compareMetricSelect.value,
      );
      renderDepartmentProfile(dep, departmentSlice, metric);
      renderPeopleLists(internalSlice);
      renderPersonalRanking(dep, internalSlice);
      renderSubdivisionTable(dep, internalSlice);
    }

    resetButton.addEventListener("click", () => {
      globalMetricSelect.value = "fade_burnout_overall";
      compareDeptOneSelect.selectedIndex = 0;
      compareDeptTwoSelect.selectedIndex = Math.min(1, compareDeptTwoSelect.options.length - 1);
      compareMetricSelect.value = "integrated_score";
      profileDepartmentSelect.selectedIndex = 0;
      profileMetricSelect.value = "fade_burnout_overall";
      personalMetricSelect.value = "integratedScore";
      populateRoleFilter(profileDepartmentSelect.value, "all");
      update();
    });

    profileDepartmentSelect.addEventListener("change", () => {
      populateRoleFilter(profileDepartmentSelect.value, roleFilter.value);
      update();
    });
    profileMetricSelect.addEventListener("change", update);
    globalMetricSelect.addEventListener("change", update);
    compareDeptOneSelect.addEventListener("change", update);
    compareDeptTwoSelect.addEventListener("change", update);
    compareMetricSelect.addEventListener("change", update);
    roleFilter.addEventListener("change", update);
    personalMetricSelect.addEventListener("change", update);
    exportWordButton.addEventListener("click", exportWord);
    exportPdfButton.addEventListener("click", exportPdf);

    renderGlobalStats();
    populateGlobalOptions();
    populateComparisonOptions();
    populateProfileOptions();
    populateInternalOptions();
    populateRoleFilter(profileDepartmentSelect.value || DATA.departments[0].department, "all");
    update();